import { Component, State, h } from '@stencil/core';
import { Item, RecipeIngredient, RootCategory, Rune, runeDetails } from '../../types/Item';

@Component({
  tag: 'item-recipe-component',
  styleUrl: 'item-recipe-component.css',
  shadow: false,
})
export class ItemRecipeComponent {
  API_URL: string = '/api';
  @State() runes: Item[] = [];
  @State() items: Item[] = [];
  @State() focusFilterRuneId:number = 0;
  @State() producedRuneFilterId: number = 0;
  @State() focusMustBeDifferentFromProducedRune: boolean = false;
  @State() isLoading: boolean = true;
  @State() errorMessage: string = '';
  @State() rootCategories:RootCategory[] = [];
  @State() orderDirection:string = "DESC";

  @State() propToSortOn:string = 'breakableRate';

  @State() refresh:boolean = false;

  currentCatId: number = 2;

  async componentWillLoad() {
    try {
      const itemsData:Item[] = await this.fetchFromApi('/items/equipments/7?offset=0&limit=500');
      const itemsData2:Item[] = await this.fetchFromApi('/items/equipments/7?offset=500&limit=500');
      this.runes = await this.fetchFromApi('/items/runes');

      this.rootCategories = await this.fetchFromApi('/rootCategories');
      this.items = await this.processItems(itemsData.concat(itemsData2));
      this.items = this.items.filter((item) => !isNaN(item.breakableRate));
    } catch (error) {
      console.error('Error fetching items:', error);
      this.errorMessage = 'Impossible de charger les items. Vérifie que l’API backend tourne.';
    } finally {
      this.isLoading = false;
    }
  }

  async processItems(itemsData: Item[]): Promise<Item[]> {
    return Promise.all(
      itemsData.map(async (item) => {
        if (!item.ResultRecipes || !item.characteristics) return item;

        item.totalCraftPrice = this.calculateCraftPrice(item);
        item._runeDetails = this.calculateRuneDetails(item);

        this.setLowestBreakableRate(item);
        this.setBenefice(item);

        return item;
      })
    );
  }

  async changeCategory(id:number){
    const itemsData:Item[] = await this.fetchFromApi(`/items/equipments/${id}?offset=0&limit=500`);
    const itemsData2:Item[] = await this.fetchFromApi(`/items/equipments/${id}?offset=500&limit=500`);
    this.items = await this.processItems(itemsData.concat(itemsData2));
    this.items = this.items.filter((item) => !isNaN(item.breakableRate));


  }

  calculateCraftPrice(item: Item): number {
    return item.ResultRecipes.reduce((total, recipe) => {
      return (
        total +
        recipe.Ingredients.reduce((sum, ingredient: RecipeIngredient) => {
          const price = ingredient.Ingredient?.averagePrices?.[0]?.averagePrice || 0;
          return sum + price * ingredient.quantity;
        }, 0)
      );
    }, 0);
  }

  calculateRuneDetails(item: Item): runeDetails[] {
    const runeDetails: runeDetails[] = [];
    let totalRunePrice = 0;
    let totalFocusRunePrice = 0;

    let focusPrice = 0;
    let bestCharToFocus:Rune;
    item.characteristics.forEach((char) => {
      if (char.from < 0 || !char.characteristic?.runes) return;

      char.characteristic.runes.forEach((rune) => {
        const density = rune.density || 1;

        
        const averagePrice = rune.rune?.averagePrices?.[0]?.averagePrice || 0;
        const value = char.to ? (char.from + char.to) / 2 : char.from;

        const pdb = (((3 * value * density * item.lvl) / 200) + 1) / Math.max(density, 1);
        const priceNoFocus = pdb * averagePrice;
        totalRunePrice += priceNoFocus;


        
        const totalPdbFocus = this.calculateFocusPdb(item, char, density);

        const priceFocus = totalPdbFocus * averagePrice;

        if(priceFocus > focusPrice){
          focusPrice = priceFocus;
          bestCharToFocus = rune;
        }

        totalFocusRunePrice = Math.max(totalFocusRunePrice, priceFocus);

        runeDetails.push({
          runeId: rune.rune?.id || 0,
          type: rune.rune?.name || 'Unknown Rune',
          quantityFocus: totalPdbFocus,
          quantityNoFocus: pdb,
          priceFocus,
          priceNoFocus,
          focusedCharacteristic: char.characteristic.name,
        });
      });
    });

    item.totalRunePrice = totalRunePrice;
    item.totalFocusRunePrice = totalFocusRunePrice;
    item.bestCharToFocus = bestCharToFocus;
    return runeDetails;
  }

  calculateFocusPdb(item: Item, char, density: number): number {
    return item.characteristics.reduce((total, focusChar) => {
      if (focusChar.from < 0) return total;

      const focusValue = focusChar.to
        ? (focusChar.from + focusChar.to) / 2
        : focusChar.from;
      const focusPdb = (((3 * focusValue * (focusChar.characteristic.runes[0]?.density || 1) * item.lvl) / 200) + 1);

      return total + (focusChar.characteristic.id === char.characteristic.id ? focusPdb : focusPdb * 0.5);
    }, 0) / Math.max(density, 1);
  }

  setLowestBreakableRate(item: Item) {
    const rateFocus = item.totalCraftPrice / item.totalFocusRunePrice;
    const rateNoFocus = item.totalCraftPrice / item.totalRunePrice;
    const coeff = Math.min(rateFocus, rateNoFocus);

    item.breakableRate = coeff;
    item.minBreakableRateFocus = rateFocus;
    item.minBreakableRateNoFocus = rateNoFocus;

    item._runeDetails.forEach((rune) => {
      rune.quantityFocus *= coeff;
      rune.quantityNoFocus *= coeff;
      rune.priceFocus *= coeff;
      rune.priceNoFocus *= coeff;
    });
  }

  setBenefice(item: Item) {
    const benefitFocus = item.totalFocusRunePrice - item.totalCraftPrice;
    const benefitNoFocus = item.totalRunePrice - item.totalCraftPrice;

    item.benefit = Math.max(benefitFocus, benefitNoFocus);
    item.benefitPercentage = item.totalCraftPrice > 0 ? (item.benefit / item.totalCraftPrice) * 100 : 0;
  }

  async fetchFromApi(route: string) {
    const response = await fetch(this.API_URL + route);
    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status}`);
    }
    return await response.json();
  }

  sortItems(){
    if(this.orderDirection === "DESC"){
      return this.items.sort((a, b) => b[this.propToSortOn] - a[this.propToSortOn]);
    } else if(this.orderDirection === "ASC"){
      return this.items.sort((a, b) => a[this.propToSortOn] - b[this.propToSortOn]);
    } else return this.items;
  }

  sortByFocusedChar(){
    if(this.focusFilterRuneId === 0) {
      return this.sortItems();
    }
    return this.sortItems().filter((item)=>{
      return item.bestCharToFocus?.rune?.id == this.focusFilterRuneId;
    })
  }

  getFilteredItems() {
    const items = this.sortByFocusedChar().filter((item) => {
      if (this.producedRuneFilterId === 0) {
        return true;
      }

      const producesSelectedRune = item._runeDetails.some((rune) => rune.runeId === this.producedRuneFilterId);
      if (!producesSelectedRune) {
        return false;
      }

      if (!this.focusMustBeDifferentFromProducedRune) {
        return true;
      }

      return item.bestCharToFocus?.rune?.id !== this.producedRuneFilterId;
    });

    return items;
  }

  render() {
    return (
      <div class="items-list">
        <h1>Items with Exact Prices and Rune Details</h1>
        <select onChange={(val)=> this.changeCategory(Number((val.target as HTMLSelectElement).value))}>
          {this.rootCategories.map((cat)=>{
            return <option value={cat.id}>{cat.name}</option>
          })}
        </select>
        <select onChange={(v)=> this.propToSortOn = ((v.target as any).value)}>
          <option value="breakableRate">Coeff</option>
          <option value="totalCraftPrice">Crafting Price</option>
        </select>
        <select onChange={(v)=>{this.orderDirection = (v.target as any).value;} }>
          <option value="DESC">DESC</option>
          <option value="ASC">ASC</option>
        </select>
        <select onChange={(v)=>{ this.focusFilterRuneId = Number((v.target as HTMLSelectElement).value)} }>
          <option value={0}>No filter</option>
          {this.runes.map((rune)=>{
            return <option value={rune.id}>{rune.name}</option>
          })}
        </select>
        <select onChange={(v)=>{ this.producedRuneFilterId = Number((v.target as HTMLSelectElement).value);} }>
          <option value={0}>Any produced rune</option>
          {this.runes.map((rune)=>{
            return <option value={rune.id}>{rune.name}</option>
          })}
        </select>
        <label>
          <input
            type="checkbox"
            checked={this.focusMustBeDifferentFromProducedRune}
            onInput={(event) => {
              this.focusMustBeDifferentFromProducedRune = (event.target as HTMLInputElement).checked;
            }}
          />
          Focus different from selected produced rune
        </label>

        {this.errorMessage ? (
          <p>{this.errorMessage}</p>
        ) : this.isLoading ? (
          <p>Loading items...</p>
        ) : (
          <table class="table">
            <thead>
              <tr>
                <th>Item Name</th>
                <th>Craft Cost</th>
                <th>Focus</th>
                <th>Minimum Break Coefficient</th>
                <th>Rune Details</th>
              </tr>
            </thead>
            <tbody>
              {this.getFilteredItems().map((item) => (
                item.totalCraftPrice > 0 && (
                  <tr key={item.id}>
                    <td>{item.name} : {item.category?.name} - lvl {item.lvl}</td>
                    <td>{item.totalCraftPrice.toFixed(0)}</td>
                    <td>{item.minBreakableRateFocus > item.minBreakableRateNoFocus ? 'No Focus' : 'Focus'}</td>
                    <td>{(Math.min(item.minBreakableRateFocus, item.minBreakableRateNoFocus)*100).toFixed(0)}</td>
                    <td>
                      {item._runeDetails.length > 0 ? (
                        <ul>
                          {item._runeDetails.map((rune) => (
                            <li key={rune.type}>
                              {rune.type}:
                              <ul>
                                <li>Quantity Focus: {rune.quantityFocus.toFixed(1)} (Total: {rune.priceFocus.toFixed(2)})</li>
                                <li>Quantity No Focus: {rune.quantityNoFocus.toFixed(1)} (Total: {rune.priceNoFocus.toFixed(2)})</li>
                              </ul>
                            </li>
                          ))}
                        </ul>
                      ) : 'N/A'}
                    </td>
                  </tr>
                )
              ))}
            </tbody>
          </table>
        )}
      </div>
    );
  }
}
